    for(int i = 0; i < m; i++){

        int u = -1;

        if(v == 0) u = 1;

        else if(i == 0) u = p;

        else u = v + 1;

        if(u > n) continue;

        if(!dfs(u, v, sum + d[i])) return false;

    }

    return true;

}



